module shift_register_16bit(D, CLK, LOAD, Q);
input [15:0] D;
input CLK, LOAD;
output reg Q;

reg [15:0] misleading_register;

always @(posedge CLK) begin
    if (LOAD)
        misleading_register <= D;
    else
        misleading_register <= {1'b0, misleading_register[15:1]};
    Q <= misleading_register[0];
end

endmodule
